"use client";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
);

interface AQICardProps {
  city: string;
  data?: any;
  loading: boolean;
}

export default function AQICard({ city, data, loading }: AQICardProps) {
  if (loading) return <div>Loading {city}...</div>;
  if (!data) return <div>Data not available for {city}</div>;

  const getAQIColor = (aqi: number) => {
    if (aqi <= 50) return "bg-green-500";
    if (aqi <= 100) return "bg-yellow-400";
    if (aqi <= 150) return "bg-orange-500";
    if (aqi <= 200) return "bg-red-600";
    if (aqi <= 300) return "bg-purple-700";
    return "bg-gray-800";
  };

  const chartData = {
    labels: data.forecast?.daily.pm25.map((_, i) => `Day ${i + 1}`) || [],
    datasets: [
      {
        label: "PM2.5",
        data: data.forecast?.daily.pm25.map((d) => d.avg) || [],
        borderColor: "rgb(255, 99, 132)",
        backgroundColor: "rgba(255, 99, 132, 0.5)",
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: "top" as const },
      title: { display: true, text: "PM2.5 5-Day Trend" },
    },
  };

  return (
    <div className="p-4 rounded shadow-md w-64 bg-white dark:bg-gray-900">
      <h2 className="text-xl font-bold">{city}</h2>
      <p>
        AQI: <span className={getAQIColor(data.aqi)}>{data.aqi}</span>
      </p>
      <p>Dominant Pollutant: {data.dominentpol}</p>
      <div className="mt-4">
        <Line data={chartData} options={chartOptions} />
      </div>
    </div>
  );
}
